// Product Inventory Analysis

const inventory = [120, 45, 0, 230, 88, 0, 310];

// reduce — total stock
const totalStock = inventory.reduce((sum, qty) => sum + qty, 0);
console.log("Total stock:", totalStock);

// some — any out-of-stock items?
const hasOutOfStock = inventory.some(qty => qty === 0);
console.log("Has out-of-stock:", hasOutOfStock);

// every — all items stocked?
const allStocked = inventory.every(qty => qty > 0);
console.log("All stocked:", allStocked);

// filter + reduce — total of only stocked items
const stockedTotal = inventory
    .filter(qty => qty > 0)
    .reduce((sum, qty) => sum + qty, 0);
console.log("Stocked total:", stockedTotal);

// Spread to copy and sort without mutating original
const sorted = [...inventory].sort((a, b) => b - a);
console.log("Sorted desc:", sorted);
console.log("Original unchanged:", inventory);

// Destructuring
const [highest, second] = sorted;
console.log(`Top two: ${highest}, ${second}`);

