// Bank Account Object — properties and methods

const account = {
    owner:        "Rahul Sharma",
    balance:      10000,
    transactions: [],

    deposit(amount) {
        if (amount <= 0) return "Invalid amount.";
        this.balance += amount;
        this.transactions.push({ type: "deposit", amount });
        return `Deposited ₹${amount}. New balance: ₹${this.balance}`;
    },

    withdraw(amount) {
        if (amount <= 0)          return "Invalid amount.";
        if (amount > this.balance) return "Insufficient funds.";
        this.balance -= amount;
        this.transactions.push({ type: "withdraw", amount });
        return `Withdrew ₹${amount}. New balance: ₹${this.balance}`;
    },

    statement() {
        console.log(`\n--- Statement: ${this.owner} ---`);
        this.transactions.forEach((t, i) => {
            console.log(`  ${i + 1}. ${t.type}: ₹${t.amount}`);
        });
        console.log(`  Balance: ₹${this.balance}`);
    },
};

console.log(account.deposit(5000));
console.log(account.withdraw(2000));
console.log(account.withdraw(20000));  // fails
account.statement();

// Destructure properties
const { owner, balance } = account;
console.log(`\n${owner}'s balance: ₹${balance}`);

